/*!
 * hls.js runtime loader — SAGA IPTV
 * Loads hls.js from CDN on demand; falls back to no-op stub if unavailable.
 * This keeps the WGT small while still getting hls.js capability online.
 */
(function(){
  if(typeof Hls !== 'undefined') return; // already loaded
  // Will be loaded on-demand by the app when needed
  window._hlsLoadPromise = null;
  window.loadHlsJs = function(){
    if(window._hlsLoadPromise) return window._hlsLoadPromise;
    window._hlsLoadPromise = new Promise(function(resolve){
      var s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/hls.js@1.5.7/dist/hls.light.min.js';
      s.onload = function(){ resolve(typeof Hls !== 'undefined' ? Hls : null); };
      s.onerror = function(){ resolve(null); };
      document.head.appendChild(s);
    });
    return window._hlsLoadPromise;
  };
})();
